mapper.sql:
WHERE a.deleted=0

    AND (sp.student_no LIKE CONCAT('%', #{query.keyword}, '%') OR sp.chinese_name LIKE CONCAT('%', #{query.keyword}, '%') OR sp.english_name LIKE CONCAT('%', #{query.keyword}, '%') OR a.title LIKE CONCAT('%', #{query.keyword}, '%'))

AND a.alert_type=#{query.alertType}
AND a.alert_level=#{query.alertLevel}
AND a.alert_status=#{query.alertStatus}

mapper.select:
SELECT  
WHERE a.student_id=#{studentId} AND a.alert_type=#{alertType}
AND a.source_id=#{sourceId}
AND a.source_id IS NULL
AND a.alert_status='PENDING' AND a.deleted=0 LIMIT 1
